(()=>{"use strict";class t{constructor(t){this.container=t,this.init()}init(){this.container.querySelectorAll(".tab").forEach((t=>{t.addEventListener("click",(()=>{this.container.querySelectorAll(".tab, .tab-content").forEach((t=>t.classList.remove("active"))),t.classList.add("active");const e=this.container.querySelector(`#${t.dataset.target}`);e&&e.classList.add("active")}))}))}}document.querySelectorAll(".tabs-container").forEach((e=>{new t(e)}))})();